// Detecta se veio um arquivo (substituir a planilha no Drive) ou se é apenas um
// SYNC: ler direto do Google Sheet conectado (mesmo id), sem upload. A interface
// usa o sync para coletar SKUs/lead times da planilha conectada só com os PDFs.
const item = $input.first();
const bin = (item.binary && item.binary.data) || null;
const hasFile = !!(bin && (bin.fileName || bin.data));
const arquivo = hasFile ? (bin.fileName || 'Planilha mestre') : 'Planilha mestre (sync do Sheet conectado)';
return [{ json: { hasFile, arquivo }, binary: item.binary }];

// Colapsa a saída da aba LEAD TIMES para 1 item, para que a leitura da aba
// de SKUs (próximo nó) execute uma única vez (e não 1x por linha de lead time).
// Os dados de lead time continuam acessíveis via $('Ler Aba Lead Times').all().
return [{ json: { ok: true } }];

// Normaliza as abas da planilha mestre para o REPLACE total do catálogo.
//   - SKUs (aba 'ANALISE DE SKUS'): DESCRIÇÃO DO PRODUTO | CODIGO | CURVAS | MEDIA MENSAL | CONSUMO DIARIA ESTIMADO
//   - Componentes (aba 'LEAD TIMES'): CODIGO | DESCRIÇÃO | UNIDADES | FABRICA/COMPRADO | FORNECEDOR | LEAD TIME DIAS
// O lead time pode vir junto na aba de SKUs ou na aba LEAD TIMES (cruzado por código).
const pick = (o, keys) => {
  for (const k of Object.keys(o)) {
    const n = k.toString().trim().toLowerCase();
    if (keys.some((t) => n.includes(t))) return o[k];
  }
  return undefined;
};
const str = (v) => (v == null ? '' : v.toString().trim());

const skuItems = $('Ler Aba SKUs').all().map((i) => i.json);
const skus = skuItems
  .map((o) => ({
    codigo: str(pick(o, ['codigo', 'código'])),
    descricao: str(pick(o, ['descri'])),
    curva: str(pick(o, ['curva'])),
    consumo_diario: pick(o, ['consumo']),
    lead_time: pick(o, ['lead', 'prazo'])
  }))
  .filter((r) => r.codigo);

let ltItems = [];
try { ltItems = $('Ler Aba Lead Times').all().map((i) => i.json); } catch (e) { ltItems = []; }
const leadtimes = ltItems
  .map((o) => ({
    codigo: str(pick(o, ['codigo', 'código'])),
    descricao: str(pick(o, ['descri'])),
    unidade: str(pick(o, ['unidad', 'und'])),
    grupo: str(pick(o, ['fabrica', 'comprado', 'f/c', 'f_c'])),
    fornecedor: str(pick(o, ['fornecedor', 'forn'])),
    lead_time: pick(o, ['lead', 'prazo', 'dias', 'tempo'])
  }))
  .filter((r) => r.codigo);

const arquivo = str($('Detect File').first().json.arquivo) || str($('Receive Planilha').first().json.body && $('Receive Planilha').first().json.body.arquivo) || 'Planilha mestre';
return [{ json: { arquivo, skus, leadtimes, total_skus: skus.length, total_leadtimes: leadtimes.length } }];
